VALUES
  ('fire-eq-tech-moex-03390', 'fire-eq-tech', 'fire-eq-tech-moex-097-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '緊急照明設備裝置完成，裝置人實施測試，下列何者錯誤？', '["試驗項目僅包括外觀試驗及性能試驗", "緊急電源採蓄電池設備，其容量應能使其持續動作60分鐘以上", "使用低照度測定用光電管照度計測其照度", "常用電源應為專用回路"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "77b297cb0114", "answer_pdf_sha1": "8d4aa5cf4033", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
