  ('fire-eq-tech-moex-03392', 'fire-eq-tech', 'fire-eq-tech-moex-097-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '緊急廣播設備裝置完成後，裝置人實施測試，有關啟動裝置之性能試驗，下列何者錯誤？', '["以麥克風進行廣播時，廣播設備之音聲警報音仍應繼續", "測試方法為依各樓層動作", "同時使2個以上任意不同樓層之啟動裝置動作時，性能應無異常", "只要未以手動回復啟動裝置及廣播設備，動作狀態即應繼續"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "77b297cb0114", "answer_pdf_sha1": "8d4aa5cf4033", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
