  ('fire-eq-tech-moex-03397', 'fire-eq-tech', 'fire-eq-tech-moex-097-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '火警自動警報設備，探測器應依裝置場所高度，選擇探測器種類裝設。同一室內之天花板或屋頂板高度 15 公尺以上未滿20公尺時，可採用型式？', '["光電式分離型一種", "差動式分布型", "補償式局限型", "定溫式特種或一種"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "36c05ea3a5ff", "answer_pdf_sha1": "439a300e3c5d", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03398', 'fire-eq-tech', 'fire-eq-tech-moex-097-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '火警自動警報設備之配線，何者有誤？', '["Ｐ型受信總機採用數個分區共用一公用線方式配線時，該公用線供應之分區數，不得超過7個", "與電力線保持30公分以上之間距", "配線採用並接式", "Ｐ型受信總機之探測器回路電阻，在50Ω以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "36c05ea3a5ff", "answer_pdf_sha1": "439a300e3c5d", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03399', 'fire-eq-tech', 'fire-eq-tech-moex-097-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '避難器具設置地點外觀檢查之判定方法，何者有誤？', '["應無因設置後之改裝被變更為個人房間或倉庫等，而不容易接近", "應進行荷重試驗，設置之居室出入口應加鎖", "應無放置妨礙接近之物品", "應無擅自不當變更收藏箱之位置"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "36c05ea3a5ff", "answer_pdf_sha1": "439a300e3c5d", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
